class TweetCounts {
public:
    TweetCounts() {
        freqMap = {
            {"minute", 60},
            {"hour", 3600},
            {"day", 86400}
        };
    }

    void recordTweet(string tweetName, int time) {
        if (tweetCounts.find(tweetName) == tweetCounts.end()) {
            tweetCounts[tweetName] = {};
        }
        tweetCounts[tweetName].push_back(time);
    }

    vector<int> getTweetCountsPerFrequency(string freq, string tweetName, int startTime, int endTime) {
        if (tweetCounts.find(tweetName) == tweetCounts.end()) {
            return {};
        }
        int chunkSize = freqMap[freq];
        vector<int> result(endTime - startTime + 1, 0);
        for (int time : tweetCounts[tweetName]) {
            if (startTime <= time && time <= endTime) {
                result[(time - startTime) / chunkSize]++;
            }
        }
        return result;
    }
private:
    unordered_map<string, vector<int>> tweetCounts;
    unordered_map<string, int> freqMap;
};
```

efficiency: HIGH
time complexity: O(n + m), where n is the number of tweets and m is the number of time chunks
space complexity: O(n + m)
energy implications: LOW

